 1	import type { FC } from 'react';
 2	
 3	import { Popover, ToggleGroup, ToggleGroupItem } from '@patternfly/react-core';
 4	import { isEmpty } from '@utils/helpers';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	type SelectedToggleProps = {
 8	  showAll: boolean;
 9	  setShowAll: (showAll: boolean) => void;
10	  selectedVmKeys: string[];
11	};
12	
13	const SelectedToggle: FC<SelectedToggleProps> = ({ selectedVmKeys, setShowAll, showAll }) => {
14	  const { t } = useForkliftTranslation();
15	
16	  const selectedToggle = (
17	    <ToggleGroupItem
18	      text={t('Selected')}
19	      isSelected={!showAll}
20	      onChange={() => {
21	        setShowAll(false);
22	      }}
23	      isDisabled={isEmpty(selectedVmKeys)}
24	    />
25	  );
26	
27	  return (
28	    <ToggleGroup>
29	      <ToggleGroupItem
30	        text={t('All')}
31	        isSelected={showAll}
32	        onChange={() => {
33	          setShowAll(true);
34	        }}
35	      />
36	      {isEmpty(selectedVmKeys) ? (
37	        <Popover triggerAction="hover" bodyContent={t('No VMs have been selected')}>
38	          {selectedToggle}
39	        </Popover>
40	      ) : (
41	        selectedToggle
42	      )}
43	    </ToggleGroup>
44	  );
45	};
46	
47	export default SelectedToggle;

